     1|import { createGateway, generateText, streamText } from 'ai';
     2|import { acquireAIQueueSlot, classifyRequestLane, type IVXAIQueueLane } from './services/ivx-ai-queue';
     3|import { estimatePromptTokens, recordProviderTelemetry } from './services/ivx-provider-telemetry';
     4|import { attemptProviderFallback, classifyProviderFailure, isFailureRetryable } from './services/ivx-ai-provider-fallback';
     5|
     6|export type IVXAIModule = 'owner-room' | 'p0-ai-assistant' | 'p1-plan-creator' | 'public-chat' | string;
     7|export type IVXAIMessageRole = 'user' | 'assistant';
     8|
     9|export type IVXAITextMessage = {
    10|  role: IVXAIMessageRole;
    11|  content: string;
    12|};
    13|
    14|export type IVXAIImageAttachment = {
    15|  url: string;
    16|  mimeType?: string | null;
    17|};
    18|
    19|/**
    20| * A non-image binary attachment (PDF for OCR, video for understanding) passed to
    21| * a multimodal model as a `file` content part. `data` may be a URL, a base64
    22| * string, or raw bytes.
    23| */
    24|export type IVXAIFileAttachment = {
    25|  data: string | Uint8Array | ArrayBuffer;
    26|  mediaType: string;
    27|  filename?: string | null;
    28|};
    29|
    30|export type IVXAIProviderMetadata = {
    31|  provider: 'chatgpt';
    32|  source: 'remote_api';
    33|  model: string;
    34|  endpoint: string | null;
    35|  runtime: 'vercel_ai_gateway';
    36|  ivxAI: {
    37|    architecture: 'ivx-ai';
    38|    phase: 'agent_runtime_v2';
    39|    layer: 'ivx_ai_runtime_wrapper';
    40|    module: string;
    41|    providerDependency: 'chatgpt_current_baseline';
    42|    requestId: string | null;
    43|    generatedAt: string;
    44|  };
    45|};
    46|
    47|export type IVXAITextResult = {
    48|  text: string;
    49|  usage: unknown;
    50|  providerMetadata: IVXAIProviderMetadata;
    51|};
    52|
    53|type IVXAIGatewayFailureContext = {
    54|  module: string;
    55|  requestId: string | null;
    56|  model: string;
    57|  endpoint: string | null;
    58|  status?: number | null;
    59|  responseBody?: unknown;
    60|};
    61|
    62|export type IVXAIConfigurationSnapshot = {
    63|  configured: boolean;
    64|  hasGatewayUrl: boolean;
    65|  hasGatewayApiKey: boolean;
    66|  model: string;
    67|  endpoint: string | null;
    68|  runtime: 'vercel_ai_gateway';
    69|  layer: 'ivx_ai_runtime_wrapper';
    70|  phase: 'agent_runtime_v2';
    71|};
    72|
    73|const GATEWAY_BASE_PATH = '/v3/ai';
    74|// Full multimodal model billed against the paid Vercel AI Gateway balance.
    75|// gpt-4o-mini is a free-tier model that Vercel rate-limits and is the weakest
    76|// vision model; gpt-4o gives real image + document analysis with no free-tier
    77|// caps. Override with IVX_AI_MODEL / PUBLIC_CHAT_MODEL / OPENAI_MODEL if needed.
    78|const DEFAULT_IVX_AI_MODEL = readTrimmed(process.env.IVX_AI_MODEL) || 'openai/gpt-4o';
    79|
    80|// Adaptive timeout floor / ceiling. Short prompts resolve fast (floor), large
    81|// reports get more headroom (ceiling). Tuned so a 12k-token report has ~90s
    82|// to complete instead of dying at the legacy 8s wall.
    83|const IVX_AI_TIMEOUT_FLOOR_MS = (() => {
    84|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_MS) || '15000', 10);
    85|  return Number.isFinite(raw) && raw > 0 ? raw : 15_000;
    86|})();
    87|const IVX_AI_TIMEOUT_CEIL_MS = (() => {
    88|  const raw = Number.parseInt(readTrimmed(process.env.IVX_AI_GATEWAY_TIMEOUT_CEIL_MS) || '120000', 10);
    89|  return Number.isFinite(raw) && raw > 0 ? raw : 120_000;
    90|})();
    91|
    92|/**
    93| * Compute an adaptive hard timeout based on the size of the work.
    94| *
    95| * Budget heuristics:
    96| *  - Base latency: floor (covers handshake + first-token latency)
    97| *  - Output budget: ~50ms per maxOutputToken (gpt-4o-mini sustains ~20 tok/s)
    98| *  - Prompt budget: ~2ms per prompt char (covers large context ingestion)
    99| * Clamped to [floor, ceiling].
   100| */
   101|export function computeAdaptiveTimeoutMs(input: {
   102|  promptChars: number;
   103|  maxOutputTokens: number | null | undefined;
   104|}): number {
   105|  const outputBudget = (input.maxOutputTokens ?? 1500) * 50;
   106|  const promptBudget = input.promptChars * 2;
   107|  const budget = IVX_AI_TIMEOUT_FLOOR_MS + outputBudget + promptBudget;
   108|  return Math.min(IVX_AI_TIMEOUT_CEIL_MS, Math.max(IVX_AI_TIMEOUT_FLOOR_MS, budget));
   109|}
   110|
   111|function runWithHardTimeout<T>(label: string, promise: Promise<T>, timeoutMs: number): Promise<T> {
   112|  return new Promise<T>((resolve, reject) => {
   113|    const timer = setTimeout(() => {
   114|      const err = new Error(`${label} timed out after ${timeoutMs}ms`);
   115|      err.name = 'IVXAIGatewayTimeoutError';
   116|      reject(err);
   117|    }, timeoutMs);
   118|    promise.then(
   119|      (value) => {
   120|        clearTimeout(timer);
   121|        resolve(value);
   122|      },
   123|      (error) => {
   124|        clearTimeout(timer);
   125|        reject(error);
   126|      },
   127|    );
   128|  });
   129|}
   130|
   131|function readTrimmed(value: unknown): string {
   132|  return typeof value === 'string' ? value.trim() : '';
   133|}
   134|
   135|function nowIso(): string {
   136|  return new Date().toISOString();
   137|}
   138|
   139|// Backend MUST talk directly to the canonical Vercel AI Gateway so the paid
   140|// AI_GATEWAY_API_KEY bearer reaches Vercel intact. Any client-facing proxy
   141|// (EXPO_PUBLIC_IVX_AI_GATEWAY_URL, e.g. ai.ivxholding.com) is intended for
   142|// the frontend only and may strip the Authorization header, which causes the
   143|// gateway to fall back to anonymous free-tier rate limits and return the
   144|// "Free tier requests on this model are rate-limited" 429 even when the
   145|// account has paid balance. The server-only override IVX_AI_GATEWAY_URL is
   146|// honored for advanced routing; otherwise we go direct to Vercel.
   147|function getIVXAIGatewayRootUrl(): string {
   148|  return readTrimmed(process.env.IVX_AI_GATEWAY_URL)
   149|    || 'https://ai-gateway.vercel.sh';
   150|}
   151|
   152|function getIVXAIGatewayApiKey(): string {
   153|  return readTrimmed(process.env.AI_GATEWAY_API_KEY);
   154|}
   155|
   156|function buildGatewayBaseUrl(rootUrl: string): string | null {
   157|  const gatewayRootUrl = readTrimmed(rootUrl).replace(/\/+$/, '');
   158|  if (!gatewayRootUrl) {
   159|    return null;
   160|  }
   161|
   162|  if (gatewayRootUrl.endsWith('/v3/ai') || gatewayRootUrl.endsWith(GATEWAY_BASE_PATH)) {
   163|    return gatewayRootUrl;
   164|  }
   165|
   166|  return new URL(GATEWAY_BASE_PATH, `${gatewayRootUrl}/`).toString().replace(/\/+$/, '');
   167|}
   168|
   169|function getGatewayBaseUrl(): string | null {
   170|  return buildGatewayBaseUrl(getIVXAIGatewayRootUrl());
   171|}
   172|
   173|function getGatewayBaseUrlCandidates(): string[] {
   174|  const configured = getGatewayBaseUrl();
   175|  const canonical = buildGatewayBaseUrl('https://ai-gateway.vercel.sh');
   176|  // Always include the canonical Vercel gateway as a fallback candidate so a
   177|  // misconfigured IVX_AI_GATEWAY_URL cannot strand the backend on a proxy that
   178|  // strips auth headers (which causes free-tier 429s on a paid account).
   179|  //
   180|  // Rork toolkit cutover (2026-07-07): the Rork toolkit URL is no longer a
   181|  // candidate. The IVX AI runtime now relies exclusively on IVX-owned
   182|  // providers: the Vercel AI Gateway (AI_GATEWAY_API_KEY) as primary, and
   183|  // OpenAI direct / Anthropic direct as fallbacks (see
   184|  // ivx-ai-provider-fallback.ts). If none of these keys are configured the
   185|  // runtime throws a clear configuration error instead of silently falling
   186|  // back to a Rork-hosted endpoint.
   187|  const candidates = [configured, canonical];
   188|
   189|  return [...new Set(candidates.filter((candidate): candidate is string => Boolean(candidate)))];
   190|}
   191|
   192|function ensureIVXAIGatewayEnvironment(): void {
   193|  const apiKey = getIVXAIGatewayApiKey();
   194|  if (!apiKey) {
   195|    // Rork toolkit cutover (2026-07-07): the Rork toolkit key is no longer
   196|    // accepted as a gateway bearer. The runtime now requires an IVX-owned
   197|    // provider key: AI_GATEWAY_API_KEY (Vercel AI Gateway, primary) or
   198|    // OPENAI_API_KEY / ANTHROPIC_API_KEY (direct fallbacks, handled by
   199|    // attemptProviderFallback in ivx-ai-provider-fallback.ts).
   200|    throw new Error(
   201|      'IVX AI runtime is not configured. Set AI_GATEWAY_API_KEY (Vercel AI Gateway) ' +
   202|        'or OPENAI_API_KEY / ANTHROPIC_API_KEY (direct fallbacks) on the backend host.',
   203|    );
   204|  }
   205|
   206|  if (!readTrimmed(process.env.AI_GATEWAY_API_KEY)) {
   207|    process.env.AI_GATEWAY_API_KEY = apiKey;
   208|  }
   209|}
   210|
   211|// Rork toolkit cutover (2026-07-07): the Rork toolkit native URL, key
   212|// resolver, isRorkToolkitBaseUrl, and callRorkToolkitNative function have been
   213|// removed. The IVX AI runtime no longer routes to toolkit.rork.com under any
   214|// condition. All AI traffic now flows through IVX-owned providers: the Vercel
   215|// AI Gateway (AI_GATEWAY_API_KEY) as primary, and OpenAI direct / Anthropic
   216|// direct as fallbacks (see ivx-ai-provider-fallback.ts).
   217|
   218|function readRecord(value: unknown): Record<string, unknown> {
   219|  return typeof value === 'object' && value !== null ? value as Record<string, unknown> : {};
   220|}
   221|
   222|function extractGatewayFailureContext(error: unknown): { status: number | null; responseBody: unknown } {
   223|  const record = readRecord(error);
   224|  const response = readRecord(record.response);
   225|  const cause = readRecord(record.cause);
   226|  const status = typeof record.statusCode === 'number'
   227|    ? record.statusCode
   228|    : typeof record.status === 'number'
   229|      ? record.status
   230|      : typeof record.responseStatus === 'number'
   231|        ? record.responseStatus
   232|        : typeof response.status === 'number'
   233|          ? response.status
   234|          : typeof cause.status === 'number'
   235|            ? cause.status
   236|            : null;
   237|  const responseBody = record.responseBody
   238|    ?? response.body
   239|    ?? response.data
   240|    ?? record.data
   241|    ?? record.body
   242|    ?? cause.responseBody
   243|    ?? cause.body
   244|    ?? null;
   245|  return { status, responseBody };
   246|}
   247|
   248|function normalizeGatewayFailure(error: unknown, context: IVXAIGatewayFailureContext): Error {
   249|  const message = error instanceof Error ? error.message : 'Gateway request failed';
   250|  const body = typeof context.responseBody === 'string'
   251|    ? context.responseBody.slice(0, 600)
   252|    : context.responseBody && typeof context.responseBody === 'object'
   253|      ? JSON.stringify(context.responseBody).slice(0, 600)
   254|      : null;
   255|  const detail = [
   256|    `IVX AI gateway request failed for ${context.module}.`,
   257|    `endpoint=${context.endpoint ?? 'unresolved'}`,
   258|    `model=${context.model}`,
   259|    context.status ? `status=${context.status}` : null,
   260|    `providerError=${message}`,
   261|    body ? `responseBody=${body}` : null,
   262|  ].filter(Boolean).join(' ');
   263|  const normalized = new Error(detail);
   264|  normalized.name = 'IVXAIGatewayRequestError';
   265|  return normalized;
   266|}
   267|
   268|function normalizeMessages(messages: IVXAITextMessage[] | undefined): IVXAITextMessage[] {
   269|  return (messages ?? [])
   270|    .map((message) => ({
   271|      role: message.role === 'assistant' ? 'assistant' as const : 'user' as const,
   272|      content: readTrimmed(message.content),
   273|    }))
   274|    .filter((message) => message.content.length > 0);
   275|}
   276|
   277|export function resolveIVXAIModel(explicitModel?: string | null, envCandidates: string[] = []): string {
   278|  const explicit = readTrimmed(explicitModel);
   279|  if (explicit) {
   280|    return explicit;
   281|  }
   282|
   283|  for (const envName of envCandidates) {
   284|    const candidate = readTrimmed(process.env[envName]);
   285|    if (candidate) {
   286|      return candidate;
   287|    }
   288|  }
   289|
   290|  return DEFAULT_IVX_AI_MODEL;
   291|}
   292|
   293|export function getIVXAIEndpoint(model: string = DEFAULT_IVX_AI_MODEL): string | null {
   294|  const baseUrl = getGatewayBaseUrl();
   295|  if (!baseUrl) {
   296|    return null;
   297|  }
   298|
   299|  return `${baseUrl}/${model}`;
   300|}
   301|
   302|export function isIVXAIConfigured(): boolean {
   303|  return getIVXAIGatewayRootUrl().length > 0 && getIVXAIGatewayApiKey().length > 0;
   304|}
   305|
   306|export function getIVXAIConfigurationSnapshot(model: string = DEFAULT_IVX_AI_MODEL): IVXAIConfigurationSnapshot {
   307|  const hasGatewayUrl = getIVXAIGatewayRootUrl().length > 0;
   308|  const hasGatewayApiKey = getIVXAIGatewayApiKey().length > 0;
   309|  return {
   310|    configured: hasGatewayUrl && hasGatewayApiKey,
   311|    hasGatewayUrl,
   312|    hasGatewayApiKey,
   313|    model,
   314|    endpoint: getIVXAIEndpoint(model),
   315|    runtime: 'vercel_ai_gateway',
   316|    layer: 'ivx_ai_runtime_wrapper',
   317|    phase: 'agent_runtime_v2',
   318|  };
   319|}
   320|
   321|export async function requestIVXAIText(input: {
   322|  module: IVXAIModule;
   323|  requestId?: string | null;
   324|  model?: string | null;
   325|  system?: string | null;
   326|  prompt?: string | null;
   327|  messages?: IVXAITextMessage[];
   328|  images?: IVXAIImageAttachment[];
   329|  files?: IVXAIFileAttachment[];
   330|  maxOutputTokens?: number;
   331|}): Promise<IVXAITextResult> {
   332|  const model = resolveIVXAIModel(input.model);
   333|  const endpoint = getIVXAIEndpoint(model);
   334|  const messages = normalizeMessages(input.messages);
   335|  const prompt = readTrimmed(input.prompt);
   336|  const system = readTrimmed(input.system);
   337|  const images = (input.images ?? [])
   338|    .map((img) => ({ url: readTrimmed(img.url), mimeType: readTrimmed(img.mimeType ?? '') || null }))
   339|    .filter((img) => img.url.length > 0);
   340|  const files = (input.files ?? []).filter(
   341|    (file) => readTrimmed(file.mediaType).length > 0 && file.data != null,
   342|  );
   343|
   344|  if (!prompt && messages.length === 0) {
   345|    throw new Error('IVX AI request requires a prompt or messages.');
   346|  }
   347|
   348|  const baseUrlCandidates = getGatewayBaseUrlCandidates();
   349|  if (baseUrlCandidates.length === 0) {
   350|    throw new Error('IVX AI runtime is not configured.');
   351|  }
   352|
   353|  console.log('[IVXAI] Routing request through IVX AI Phase 1 wrapper:', {
   354|    module: input.module,
   355|    requestId: input.requestId ?? null,
   356|    model,
   357|    endpoint,
   358|    baseUrlCandidates,
   359|    hasSystem: system.length > 0,
   360|    promptLength: prompt.length,
   361|    messageCount: messages.length,
   362|    authKeySource: 'AI_GATEWAY_API_KEY',
   363|    requestShape: messages.length > 0 ? 'messages' : 'prompt',
   364|    maxOutputTokens: input.maxOutputTokens ?? null,
   365|    phase: 'agent_runtime_v2',
   366|    layer: 'ivx_ai_runtime_wrapper',
   367|  });
   368|
   369|  // Adaptive timeout + queue gating: long prompts/reports get more time and a
   370|  // dedicated lane so they cannot block normal chat under contention.
   371|  const promptChars = prompt.length + system.length + messages.reduce((sum, m) => sum + m.content.length, 0);
   372|  const adaptiveTimeoutMs = computeAdaptiveTimeoutMs({ promptChars, maxOutputTokens: input.maxOutputTokens });
   373|  const queueLane: IVXAIQueueLane = classifyRequestLane({ promptChars, maxOutputTokens: input.maxOutputTokens });
   374|  const queueSlot = await acquireAIQueueSlot(queueLane);
   375|  const callStartedAt = Date.now();
   376|
   377|  let result: Awaited<ReturnType<typeof generateText>> | null = null;
   378|  let lastError: unknown = null;
   379|  let lastFailure: { status: number | null; responseBody: unknown } = { status: null, responseBody: null };
   380|  let successfulBaseUrl = baseUrlCandidates[0];
   381|  let retryCount = 0;
   382|
   383|  for (const baseURL of baseUrlCandidates) {
   384|    ensureIVXAIGatewayEnvironment();
   385|    try {
   386|      const gatewayProvider = createGateway({
   387|        apiKey: getIVXAIGatewayApiKey(),
   388|        baseURL,
   389|      });
   390|      const callTimeoutMs = adaptiveTimeoutMs;
   391|      if (images.length > 0 || files.length > 0) {
   392|        // Multimodal request: build a single user message with text + image/file
   393|        // parts so multimodal models (gpt-4o family for images/PDF OCR, video-
   394|        // capable models for video) can actually see the attachments.
   395|        const baseMessages = messages.length > 0
   396|          ? messages.slice(0, -1)
   397|          : [];
   398|        const lastTextMessage = messages.length > 0 ? messages[messages.length - 1] : null;
   399|        const userText = readTrimmed(
   400|          (lastTextMessage && lastTextMessage.role === 'user' ? lastTextMessage.content : '') || prompt
   401|        ) || 'Describe the attached file(s).';
   402|        const multimodalUser = {
   403|          role: 'user' as const,
   404|          content: [
   405|            { type: 'text' as const, text: userText },
   406|            ...images.map((img) => ({ type: 'image' as const, image: img.url })),
   407|            ...files.map((file) => ({ type: 'file' as const, data: file.data, mediaType: file.mediaType })),
   408|          ],
   409|        };
   410|        const finalMessages = lastTextMessage && lastTextMessage.role === 'user'
   411|          ? [...baseMessages, multimodalUser]
   412|          : [...messages, multimodalUser];
   413|        result = await runWithHardTimeout('IVX AI gateway (multimodal)', generateText({
   414|          model: gatewayProvider(model),
   415|          system: system.length > 0 ? system : undefined,
   416|          maxOutputTokens: input.maxOutputTokens,
   417|          // eslint-disable-next-line @typescript-eslint/no-explicit-any
   418|          messages: finalMessages as any,
   419|        }), callTimeoutMs);
   420|      } else {
   421|        result = messages.length > 0
   422|          ? await runWithHardTimeout('IVX AI gateway (messages)', generateText({
   423|              model: gatewayProvider(model),
   424|              system: system.length > 0 ? system : undefined,
   425|              maxOutputTokens: input.maxOutputTokens,
   426|              messages,
   427|            }), callTimeoutMs)
   428|          : await runWithHardTimeout('IVX AI gateway (prompt)', generateText({
   429|              model: gatewayProvider(model),
   430|              system: system.length > 0 ? system : undefined,
   431|              maxOutputTokens: input.maxOutputTokens,
   432|              prompt,
   433|            }), callTimeoutMs);
   434|      }
   435|      successfulBaseUrl = baseURL;
   436|      break;
   437|    } catch (error) {
   438|      retryCount += 1;
   439|      const failure = extractGatewayFailureContext(error);
   440|      lastError = error;
   441|      lastFailure = failure;
   442|      console.error('[IVXAI] Gateway request failed:', {
   443|        module: input.module,
   444|        requestId: input.requestId ?? null,
   445|        model,
   446|            endpoint: `${baseURL}/${model}`,
   447|        status: failure.status,
   448|        error: error instanceof Error ? error.message : 'Gateway request failed',
   449|        responseBodyType: typeof failure.responseBody,
   450|        responseBodyPreview: typeof failure.responseBody === 'string'
   451|          ? failure.responseBody.slice(0, 400)
   452|          : failure.responseBody && typeof failure.responseBody === 'object'
   453|            ? JSON.stringify(failure.responseBody).slice(0, 400)
   454|            : null,
   455|        errorName: error instanceof Error ? error.name : null,
   456|      });
   457|    }
   458|  }
   459|
   460|  if (!result) {
   461|    queueSlot.release();
   462|    const failureMessage = lastError instanceof Error ? lastError.message : 'Gateway request failed';
   463|    const isTimeout = lastError instanceof Error && lastError.name === 'IVXAIGatewayTimeoutError';
   464|
   465|    // Multi-provider fallback chain. Only invoked when:
   466|    //   - all primary gateway base URLs failed
   467|    //   - failure is in a retryable class (timeout / rate_limit / quota / 5xx / network)
   468|    //   - at least one fallback provider has its env key configured
   469|    // Fallbacks NEVER log API keys or prompt content.
   470|    const failureClass = classifyProviderFailure(lastError);
   471|    if (isFailureRetryable(failureClass)) {
   472|      const fallbackResult = await attemptProviderFallback({
   473|        module: String(input.module),
   474|        requestId: input.requestId ?? null,
   475|        system,
   476|        prompt,
   477|        messages,
   478|        maxOutputTokens: input.maxOutputTokens ?? null,
   479|        timeoutMs: adaptiveTimeoutMs,
   480|      });
   481|      if (fallbackResult) {
   482|        const fallbackMetadata: IVXAIProviderMetadata = {
   483|          provider: 'chatgpt',
   484|          source: 'remote_api',
   485|          model: fallbackResult.model,
   486|          endpoint: null,
   487|          runtime: 'vercel_ai_gateway',
   488|          ivxAI: {
   489|            architecture: 'ivx-ai',
   490|            phase: 'agent_runtime_v2',
   491|            layer: 'ivx_ai_runtime_wrapper',
   492|            module: input.module,
   493|            providerDependency: 'chatgpt_current_baseline',
   494|            requestId: input.requestId ?? null,
   495|            generatedAt: nowIso(),
   496|          },
   497|        };
   498|        recordProviderTelemetry({
   499|          traceId: input.requestId ?? null,
   500|          module: String(input.module),
   501|          model: fallbackResult.model,
   502|          endpoint: null,
   503|          promptChars,
   504|          promptTokensEstimated: estimatePromptTokens(promptChars),
   505|          completionTokens: null,
   506|          totalTokens: null,
   507|          latencyMs: Date.now() - callStartedAt,
   508|          retryCount: Math.max(0, retryCount - 1),
   509|          status: 'ok',
   510|          httpStatus: 200,
   511|          failureReason: `primary_failed_${failureClass}_fallback=${fallbackResult.provider}`,
   512|          maxOutputTokens: input.maxOutputTokens ?? null,
   513|          adaptiveTimeoutMs,
   514|          queueWaitMs: queueSlot.waitMs,
   515|        });
   516|        console.log('[IVXAI] Recovered via fallback provider:', {
   517|          module: input.module,
   518|          requestId: input.requestId ?? null,
   519|          primaryFailureClass: failureClass,
   520|          fallbackProvider: fallbackResult.provider,
   521|          fallbackModel: fallbackResult.model,
   522|        });
   523|        return {
   524|          text: fallbackResult.text,
   525|          usage: null,
   526|          providerMetadata: fallbackMetadata,
   527|        };
   528|      }
   529|    }
   530|
   531|    recordProviderTelemetry({
   532|      traceId: input.requestId ?? null,
   533|      module: String(input.module),
   534|      model,
